// Categorize documents by expiration urgency
const documents = $input.all().map(item => item.json);
const now = new Date();

const categories = {
  expired: [],
  expiring_30: [],
  expiring_60: [],
  expiring_90: []
};

const reminders = [];

for (const doc of documents) {
  if (!doc.document || !doc.document.fields) continue;

  const fields = doc.document.fields;
  const expirationStr = fields.expiration_date?.stringValue;
  if (!expirationStr) continue;

  const expDate = new Date(expirationStr);
  const daysUntil = Math.ceil((expDate - now) / (1000 * 60 * 60 * 24));
  const docId = doc.document.name.split('/').pop();

  const docInfo = {
    document_id: docId,
    entity_id: fields.entity_id?.stringValue || '',
    filename: fields.filename?.stringValue || '',
    document_type: fields.document_type?.stringValue || '',
    expiration_date: expirationStr,
    days_until_expiry: daysUntil
  };

  if (daysUntil < 0) {
    categories.expired.push(docInfo);
    reminders.push({ ...docInfo, urgency: 'expired', reminder_type: 'expiration_warning' });
  } else if (daysUntil <= 30) {
    categories.expiring_30.push(docInfo);
    reminders.push({ ...docInfo, urgency: 'critical', reminder_type: 'expiration_warning' });
  } else if (daysUntil <= 60) {
    categories.expiring_60.push(docInfo);
    reminders.push({ ...docInfo, urgency: 'warning', reminder_type: 'expiration_warning' });
  } else {
    categories.expiring_90.push(docInfo);
    reminders.push({ ...docInfo, urgency: 'notice', reminder_type: 'expiration_warning' });
  }
}

return [{
  json: {
    categories: categories,
    reminders: reminders,
    summary: {
      total: reminders.length,
      expired: categories.expired.length,
      expiring_30_days: categories.expiring_30.length,
      expiring_60_days: categories.expiring_60.length,
      expiring_90_days: categories.expiring_90.length
    },
    checked_at: new Date().toISOString()
  }
}];

// Create individual reminder records for each expiring document
const data = $input.first().json;
const reminders = data.reminders || [];

const reminderRecords = reminders.map((r, idx) => ({
  json: {
    reminder_id: `auto_${Date.now()}_${idx}`,
    entity_id: r.entity_id,
    document_id: r.document_id,
    document_name: r.filename,
    document_type: r.document_type,
    expiration_date: r.expiration_date,
    days_until_expiry: r.days_until_expiry,
    urgency: r.urgency,
    reminder_type: r.reminder_type,
    status: 'pending',
    created_at: new Date().toISOString()
  }
}));

// Also pass through the summary for the digest email
reminderRecords.push({
  json: {
    _is_summary: true,
    summary: data.summary,
    categories: data.categories,
    checked_at: data.checked_at
  }
});

return reminderRecords;
